UPDATE post
SET hit = hit + 1
where post_idx = #{post_idx}

mapper.select:
select * from(
SELECT ROW_NUMBER() OVER(ORDER BY post_idx DESC) AS rnum, a.*
from(
select * from post
where post_status = 0
and category_idx=2
order by post_idx DESC
) a
) c inner join member m on c.member_idx=m.member_idx
where c.rnum Between #{begin} and #{end}
order by post_idx desc

select * from(
SELECT ROW_NUMBER() OVER(ORDER BY post_idx DESC) AS rnum, a.*
from(
select * from post
where post_status = 0
and member_idx = #{member_idx}
and category_idx=2
order by post_idx DESC
) a
) c inner join member m on c.member_idx=m.member_idx
where c.rnum Between #{begin} and #{end}
order by post_idx desc

select *
from post p inner join member m
where p.member_idx=m.member_idx and p.post_idx = #{post_idx}

