UPDATE post p
INNER JOIN file f ON p.post_idx = f.post_idx

    p.post_title = #{post_title},
    p.post_content = #{post_content}

WHERE p.post_idx = #{post_idx}

mapper.select:
SELECT a.*
FROM (
SELECT ROW_NUMBER() OVER(ORDER BY post_idx DESC) AS rnum, p.*, m.member_nickname
FROM post p LEFT JOIN member m ON p.member_idx = m.member_idx




                p.post_title LIKE CONCAT ('%', #{searchValue}, '%')


                p.post_content LIKE CONCAT('%', #{searchValue}, '%')


                m.member_nickname LIKE CONCAT('%', #{searchValue}, '%')


        and p.member_idx = #{member_idx}


)a
where a.rnum BETWEEN #{begin} AND #{end};

